    55→function getIgnoredSettingsFromContent(settingsContent: string): string[] {
    56→	const parsed = parse(settingsContent);
    57→	return parsed ? parsed['settingsSync.ignoredSettings'] || parsed['sync.ignoredSettings'] || [] : [];
    58→}
