    60→export function removeComments(content: string, formattingOptions: FormattingOptions): string {
    61→	const source = parse(content) || {};
    62→	let result = '{}';
    63→	for (const key of Object.keys(source)) {
    64→		const edits = setProperty(result, [key], source[key], formattingOptions);
    65→		result = applyEdits(result, edits);
    66→	}
    67→	return result;
    68→}
