   104→export function merge(originalLocalContent: string, originalRemoteContent: string, baseContent: string | null, ignoredSettings: string[], resolvedConflicts: { key: string; value: any | undefined }[], formattingOptions: FormattingOptions): IMergeResult {
   105→
   106→	const localContentWithoutIgnoredSettings = updateIgnoredSettings(originalLocalContent, originalRemoteContent, ignoredSettings, formattingOptions);
   107→	const localForwarded = baseContent !== localContentWithoutIgnoredSettings;
   108→	const remoteForwarded = baseContent !== originalRemoteContent;
   109→
   110→	/* no changes */
   111→	if (!localForwarded && !remoteForwarded) {
   112→		return { conflictsSettings: [], localContent: null, remoteContent: null, hasConflicts: false };
   113→	}
   114→
   115→	/* local has changed and remote has not */
   116→	if (localForwarded && !remoteForwarded) {
   117→		return { conflictsSettings: [], localContent: null, remoteContent: localContentWithoutIgnoredSettings, hasConflicts: false };
   118→	}
   119→
   120→	/* remote has changed and local has not */
   121→	if (remoteForwarded && !localForwarded) {
   122→		return { conflictsSettings: [], localContent: updateIgnoredSettings(originalRemoteContent, originalLocalContent, ignoredSettings, formattingOptions), remoteContent: null, hasConflicts: false };
   123→	}
   124→
   125→	/* local is empty and not synced before */
   126→	if (baseContent === null && isEmpty(originalLocalContent)) {
   127→		const localContent = areSame(originalLocalContent, originalRemoteContent, ignoredSettings) ? null : updateIgnoredSettings(originalRemoteContent, originalLocalContent, ignoredSettings, formattingOptions);
   128→		return { conflictsSettings: [], localContent, remoteContent: null, hasConflicts: false };
   129→	}
   130→
   131→	/* remote and local has changed */
   132→	let localContent = originalLocalContent;
   133→	let remoteContent = originalRemoteContent;
   134→	const local = parse(originalLocalContent);
   135→	const remote = parse(originalRemoteContent);
   136→	const base = baseContent ? parse(baseContent) : null;
   137→
   138→	const ignored = ignoredSettings.reduce((set, key) => { set.add(key); return set; }, new Set<string>());
   139→	const localToRemote = compare(local, remote, ignored);
   140→	const baseToLocal = compare(base, local, ignored);
   141→	const baseToRemote = compare(base, remote, ignored);
   142→
   143→	const conflicts: Map<string, IConflictSetting> = new Map<string, IConflictSetting>();
   144→	const handledConflicts: Set<string> = new Set<string>();
   145→	const handleConflict = (conflictKey: string): void => {
   146→		handledConflicts.add(conflictKey);
   147→		const resolvedConflict = resolvedConflicts.filter(({ key }) => key === conflictKey)[0];
   148→		if (resolvedConflict) {
   149→			localContent = contentUtil.edit(localContent, [conflictKey], resolvedConflict.value, formattingOptions);
   150→			remoteContent = contentUtil.edit(remoteContent, [conflictKey], resolvedConflict.value, formattingOptions);
   151→		} else {
   152→			conflicts.set(conflictKey, { key: conflictKey, localValue: local[conflictKey], remoteValue: remote[conflictKey] });
   153→		}
   154→	};
   155→
   156→	// Removed settings in Local
   157→	for (const key of baseToLocal.removed.values()) {
   158→		// Conflict - Got updated in remote.
   159→		if (baseToRemote.updated.has(key)) {
   160→			handleConflict(key);
   161→		}
   162→		// Also remove in remote
   163→		else {
   164→			remoteContent = contentUtil.edit(remoteContent, [key], undefined, formattingOptions);
   165→		}
   166→	}
   167→
   168→	// Removed settings in Remote
   169→	for (const key of baseToRemote.removed.values()) {
   170→		if (handledConflicts.has(key)) {
   171→			continue;
   172→		}
   173→		// Conflict - Got updated in local
   174→		if (baseToLocal.updated.has(key)) {
   175→			handleConflict(key);
   176→		}
   177→		// Also remove in locals
   178→		else {
   179→			localContent = contentUtil.edit(localContent, [key], undefined, formattingOptions);
   180→		}
   181→	}
   182→
   183→	// Updated settings in Local
   184→	for (const key of baseToLocal.updated.values()) {
   185→		if (handledConflicts.has(key)) {
   186→			continue;
   187→		}
   188→		// Got updated in remote
   189→		if (baseToRemote.updated.has(key)) {
   190→			// Has different value
   191→			if (localToRemote.updated.has(key)) {
   192→				handleConflict(key);
   193→			}
   194→		} else {
   195→			remoteContent = contentUtil.edit(remoteContent, [key], local[key], formattingOptions);
   196→		}
   197→	}
   198→
   199→	// Updated settings in Remote
   200→	for (const key of baseToRemote.updated.values()) {
   201→		if (handledConflicts.has(key)) {
   202→			continue;
   203→		}
   204→		// Got updated in local
   205→		if (baseToLocal.updated.has(key)) {
   206→			// Has different value
   207→			if (localToRemote.updated.has(key)) {
   208→				handleConflict(key);
   209→			}
   210→		} else {
   211→			localContent = contentUtil.edit(localContent, [key], remote[key], formattingOptions);
   212→		}
   213→	}
   214→
   215→	// Added settings in Local
   216→	for (const key of baseToLocal.added.values()) {
   217→		if (handledConflicts.has(key)) {
   218→			continue;
   219→		}
   220→		// Got added in remote
   221→		if (baseToRemote.added.has(key)) {
   222→			// Has different value
   223→			if (localToRemote.updated.has(key)) {
   224→				handleConflict(key);
   225→			}
   226→		} else {
   227→			remoteContent = addSetting(key, localContent, remoteContent, formattingOptions);
   228→		}
   229→	}
   230→
   231→	// Added settings in remote
   232→	for (const key of baseToRemote.added.values()) {
   233→		if (handledConflicts.has(key)) {
   234→			continue;
   235→		}
   236→		// Got added in local
   237→		if (baseToLocal.added.has(key)) {
   238→			// Has different value
   239→			if (localToRemote.updated.has(key)) {
   240→				handleConflict(key);
   241→			}
   242→		} else {
   243→			localContent = addSetting(key, remoteContent, localContent, formattingOptions);
   244→		}
   245→	}
   246→
   247→	const hasConflicts = conflicts.size > 0 || !areSame(localContent, remoteContent, ignoredSettings);
   248→	const hasLocalChanged = hasConflicts || !areSame(localContent, originalLocalContent, []);
   249→	const hasRemoteChanged = hasConflicts || !areSame(remoteContent, originalRemoteContent, []);
   250→	return { localContent: hasLocalChanged ? localContent : null, remoteContent: hasRemoteChanged ? remoteContent : null, conflictsSettings: [...conflicts.values()], hasConflicts };
   251→}
   252→
   253→function areSame(localContent: string, remoteContent: string, ignoredSettings: string[]): boolean {
   254→	if (localContent === remoteContent) {
   255→		return true;
   256→	}
   257→
   258→	const local = parse(localContent);
   259→	const remote = parse(remoteContent);
   260→	const ignored = ignoredSettings.reduce((set, key) => { set.add(key); return set; }, new Set<string>());
   261→	const localTree = parseSettings(localContent).filter(node => !(node.setting && ignored.has(node.setting.key)));
   262→	const remoteTree = parseSettings(remoteContent).filter(node => !(node.setting && ignored.has(node.setting.key)));
   263→
   264→	if (localTree.length !== remoteTree.length) {
   265→		return false;
   266→	}
   267→
   268→	for (let index = 0; index < localTree.length; index++) {
   269→		const localNode = localTree[index];
   270→		const remoteNode = remoteTree[index];
   271→		if (localNode.setting && remoteNode.setting) {
   272→			if (localNode.setting.key !== remoteNode.setting.key) {
   273→				return false;
   274→			}
   275→			if (!objects.equals(local[localNode.setting.key], remote[localNode.setting.key])) {
   276→				return false;
   277→			}
   278→		} else if (!localNode.setting && !remoteNode.setting) {
   279→			if (localNode.value !== remoteNode.value) {
   280→				return false;
   281→			}
   282→		} else {
   283→			return false;
   284→		}
   285→	}
   286→
   287→	return true;
   288→}
